from itertools import permutations

class Solution:
    def maximumUnits(self, boxTypes, truckSize):
        best = 0
        for order in permutations(range(len(boxTypes))):
            remaining = truckSize
            total = 0
            for i in order:
                count, units = boxTypes[i]
                take = min(remaining, count)
                total += take * units
                remaining -= take
                if remaining == 0:
                    break
            best = max(best, total)
        return best

