class Solution:
    def maximumUnits(self, boxTypes, truckSize):
        boxTypes = sorted(boxTypes, key=lambda b: -b[1])
        remaining = truckSize
        total = 0
        for count, units in boxTypes:
            take = min(remaining, count)
            total += take * units
            remaining -= take
            if remaining == 0:
                break
        return total

