var maximumUnits = function(boxTypes, truckSize) {
    const sorted = boxTypes.slice().sort((a, b) => b[1] - a[1]);
    let remaining = truckSize;
    let total = 0;
    for (const [count, units] of sorted) {
        const take = Math.min(remaining, count);
        total += take * units;
        remaining -= take;
        if (remaining === 0) break;
    }
    return total;
};
